1100→                pOut = nn_mat_mul_kernel_q15_q15_q7_bias_2sft(wt_tmp_buf, in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim + 1, pre_rshift, out_scale, post_rshift, bias, pOut);
1101→                pBuffer = in_tmp_buf;
1102→            }
1103→        }
1104→    }
1105→
1106→    if (pBuffer != in_tmp_buf)
1107→    {
1108→        const q7_t *pA = ker_weight;
1109→        int i;
1110→
1111→        for (i = 0; i < out_tensor_ch; i++)
1112→        {
1113→            q31_t   sum = bias[i];
1114→            q15_t   *pB = in_tmp_buf;
1115→
1116→            /* basically each time it process 4 entries */
1117→            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;
1118→
1119→            while (colCnt)
1120→            {
1121→                q31_t     inA1, inA2;
1122→                q31_t     inB1, inB2;
1123→
1124→                pA = (q7_t *) read_and_pad((void *)pA, &inA1, &inA2);
1125→                inB1 = *__SIMD32(pB)++;
1126→                sum = NDS_DSP_KMADA(sum, inA1, inB1);
1127→                inB2 = *__SIMD32(pB)++;
1128→                sum = NDS_DSP_KMADA(sum, inA2, inB2);
1129→
1130→                colCnt--;
1131→            }
1132→            colCnt = 3 * ker_dim * ker_dim & 0x3;
1133→            while (colCnt)
1134→            {
1135→                q7_t      inA1 = *pA++;
1136→                q15_t     inB1 = *pB++;
1137→                sum += inA1 * inB1;
1138→                colCnt--;
1139→            }
1140→
1141→            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
1142→            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
1143→        }
1144→    }
1145→#else
1146→    uint16_t  i, j, k, l, m, n;
1147→    int       conv_out;
1148→    long in_row, in_col;
1149→
1150→    for (i = 0; i < out_tensor_ch; i++)
1151→    {
1152→        for (j = 0; j < out_tensor_dim; j++)
1153→        {
1154→            for (k = 0; k < out_tensor_dim; k++)
1155→            {
1156→                conv_out = bias[i];
1157→                for (m = 0; m < ker_dim; m++)
1158→                {
1159→                    for (n = 0; n < ker_dim; n++)
1160→                    {
1161→                        /* if-for implementation */
1162→                        in_row = stride * j + m - pad;
1163→                        in_col = stride * k + n - pad;
1164→                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
1165→                        {
1166→                            for (l = 0; l < 3; l++)
1167→                            {
1168→                                conv_out +=
1169→                                    in_tensor[(in_row * in_tensor_dim + in_col) * 3 + l]
1170→                                    * ker_weight[i * 3 * ker_dim * ker_dim + (m * ker_dim + n) * 3 + l];
1171→                            }
1172→                        }
1173→                    }
1174→                }
1175→                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
1176→                out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 8);
1177→            }
1178→        }
1179→    }
1180→#endif
1181→
1182→    return 0;
1183→}
