/** @file*/

#include "internal_nn_math.h"
#include "riscv_nn_support.h"

//// Convolution Functions
int32_t riscv_nn_conv_HWC_s8_s8_s8_RGB_sym_bias_fast(const q7_t * in_tensor,
                                            const uint16_t in_tensor_dim,
                                            const q7_t * ker_weight,
                                            const uint16_t out_tensor_ch,
                                            const uint16_t ker_dim,
                                            const uint16_t pad,
                                            const uint16_t stride,
                                            const q31_t * bias,
                                            const uint16_t pre_rshift,
                                            const uint16_t out_scale,
                                            const uint16_t post_rshift,
                                            q7_t * out_tensor,
                                            const uint16_t out_tensor_dim,
                                            q15_t * in_tmp_buf,
                                            q15_t * wt_tmp_buf)
{
#ifdef ENA_EMPTY_FUN
    //empty body
#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
    long   i_out_y, i_out_x, i_ker_y, i_ker_x;

    /*
     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
     *  im2col are done to output in q15_t format from q7_t input
     */
    q7_t *pBuffer = (q7_t *)in_tmp_buf;
    q7_t *pOut = out_tensor;

    long buf_len = (3 * ker_dim * ker_dim);
    long vl;

    // This part implements the im2col function
    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            // init in_tmp_buf
            long len = buf_len;
            q7_t *pBuffer2 = pBuffer;
            vl = __riscv_vsetvl_e8m8(len);
            vint8m8_t vZero = __riscv_vand(__riscv_vundefined_i8m8(), 0x0, vl);     //const zero for redsum
            while(len > 0)
            {
                __riscv_vse8(pBuffer2, vZero, vl);
                len -= vl;
                pBuffer2 += vl;
                vl = __riscv_vsetvl_e8m8(len);
            }

            // if (i_ker_y < 0)
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < 0; i_ker_y++)
            {
                pBuffer += ker_dim * 3;
            }

            long bound_y = ((i_out_y * stride - pad + ker_dim) < in_tensor_dim)? (i_out_y * stride - pad + ker_dim) : in_tensor_dim;
            for (; i_ker_y < bound_y; i_ker_y++)
            {
                // if (i_ker_x < 0)
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < 0; i_ker_x++)
                {
                    pBuffer += 3;
                }

                long bound_x = (i_out_x * stride - pad + ker_dim < in_tensor_dim)? (i_out_x * stride - pad + ker_dim) : in_tensor_dim;
                const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
                long loop = (bound_x - i_ker_x)*3;
                i_ker_x = bound_x;
                while(loop > 0)
                {
                    vl = __riscv_vsetvl_e8m8(loop);
                    vint8m8_t vpPixel = __riscv_vle8_v_i8m8(pPixel, vl);
                    __riscv_vse8(pBuffer, vpPixel, vl);
                    pPixel += vl;
                    pBuffer += vl;
                    loop -= vl;
                }

                // if (i_ker_x >= in_tensor_dim)
                for ( ; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    pBuffer += 3;
                }
            }

            // if (i_ker_y >= in_tensor_dim)
            for (; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                pBuffer += ker_dim * 3;
            }

            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim))
            {
                pOut = nn_mat_mul_kernel_q7_bias_2sft((q7_t *)ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim, pre_rshift, out_scale, post_rshift, bias, pOut);
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }
    }

#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        unsigned vl;
        const q7_t *p_wt = ker_weight;
        int       i;
        uint16_t  colCnt = 3 * ker_dim * ker_dim;
        // long vlenb = NDS_VEC_CSR_GET_VLENB();

#if (__clang__)
        register const long zero asm ("x0") = 0;
#else
        register const long zero asm ("x0");
#endif

        vl = __riscv_vsetvl_e32m1(1);
        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), zero, vl);     //const zero for redsum

        for (i = 0; i < out_tensor_ch; i++)
        {
            q7_t      *p_in = (q7_t*)in_tmp_buf;
            uint16_t colCnt2 = colCnt;

            //clear v0~v7
            vl = __riscv_vsetvl_e32m8(colCnt);
            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), zero, vl);

            // while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
            // {
            //     NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            //     //load src1
            //     NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
            //     //load src2
            //     NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
            //     //bump pointers and update loop counter
            //     colCnt2 -= vl;
            //     p_wt += vl;
            //     p_in += vl;
            //     //set the proper avl/SEW/LMUL values for vd4dot
            //     vl >>= 2;
            //     NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            //     //acc += src1 * src2
            //     NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            // }

            //extra process for the case of elements to be dot producted is not a mutiple of 4
            while(colCnt2 > 0)
            {
                //clean one of the dot product source
                vl = __riscv_vsetvlmax_e8m8();
                vint8m8_t vP_wt_i8m8 = __riscv_vand(__riscv_vundefined_i8m8(), zero, vl);

                vl = __riscv_vsetvl_e8m8(colCnt2);
                //load src1
                vP_wt_i8m8 = __riscv_vle8_v_i8m8_tu(vP_wt_i8m8, p_wt, vl);
                //load src2
                vint8m8_t vP_in_i8m8 = __riscv_vle8_v_i8m8(p_in, vl);
                //bump pointers and update loop counter
                colCnt2 -= vl;
                p_wt += vl;
                p_in += vl;
                //set the proper avl/SEW/LMUL values for vd4dot
                //remember to deal with the avl of vd4dot is not a multiple of 4 case
                vl = __riscv_vsetvl_e32m8(vl);
                //acc += src1 * src2
                vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_i8m8, vl);
            }

            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
            vint32m1_t vSum_i32 = __riscv_vredsum(vAccumulator, vZero, vl);

            //add bias back
            vl = __riscv_vsetvl_e32m1(1);
            vint32m1_t vBias_i32 = __riscv_vle32_v_i32m1(bias, vl);
            vSum_i32 = __riscv_vadd(vSum_i32, vBias_i32, vl);

            //2-stage shift
            vSum_i32 = __riscv_vsra(vSum_i32, pre_rshift, vl);
            vSum_i32 = __riscv_vmul(vSum_i32, out_scale, vl);
            vSum_i32 = __riscv_vadd(vSum_i32, NN_ROUND(post_rshift), vl);

            //scale down, clip and store the results
            vl = __riscv_vsetvl_e16mf2(1);
            vint16mf2_t vSum_i16 = __riscv_vnsra(vSum_i32, post_rshift, vl);
            vl = __riscv_vsetvl_e8mf4(1);
            vint8mf4_t vSum_i8 = __riscv_vnclip(vSum_i16, zero, __RISCV_VXRM_RNU, vl);
            __riscv_vse8(pOut, vSum_i8, vl);
            bias += vl;
            pOut += vl;
        }
    }
#elif (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ISA_ZVQMAC)
    /* left-over because odd number of output pixels */
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        long i;
        /* basically each time it process 4 entries */
        long colCnt = (3 * ker_dim * ker_dim);

        //set SEW for 1st time VMV_S_X
        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
        vl = __riscv_vsetvl_e32m8(colCnt);

        for (i = 0; i < out_tensor_ch; i++)
        {
            q31_t sum = bias[i];
            q7_t *pB = (q7_t*)in_tmp_buf;
            long colCnt2 = colCnt;

            //init
            vint32m1_t vBias = __riscv_vmv_s_x_i32m1(sum, vl);
            //clear v8~v15 (acc)
            vint32m8_t vAcc = __riscv_vundefined_i32m8();
            vAcc = __riscv_vand_tu(vAcc, vAcc, 0, vl);

            while(colCnt2 > 0)
            {
                vl = __riscv_vsetvl_e8m2(colCnt2);
                vint8m2_t vPa_i8 = __riscv_vundefined_i8m2();
                vint8m2_t vPb_i8 = __riscv_vundefined_i8m2();
                vPa_i8 = __riscv_vle8_tu(vPa_i8, pA, vl);
                vPb_i8 = __riscv_vle8_tu(vPb_i8, pB, vl);
                vAcc = __riscv_vqmacc_vv_i32m8_tu(vAcc, vPa_i8, vPb_i8, vl);
                //bump pointers and update loop counter
                colCnt2 -= vl;
                pA += vl;
                pB += vl;
            }

            vl = __riscv_vsetvl_e32m8(colCnt);    //note the avl here
            vint32m1_t vAcc_sum = __riscv_vredsum(vAcc, vBias, vl);
            //move vr results to gpr
            sum = __riscv_vmv_x(vAcc_sum);

            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = NDS_ISA_SATS((sum >> post_rshift), 8);
        }
    }
#endif
#elif defined(ENA_VEC_ISA)
#ifdef ENA_TILING
#if (NDS_VEC_RVV_VERSION >= 1000)
    /*
     * Direct convolution with fused bias + requantize.
     * Vectorizes across out_tensor_ch: vqmacc.vx accumulates one input scalar
     * against the full transposed weight row (all output channels).
     * Processes 4 output pixels at a time, sharing weight loads.
     * Eliminates im2col buffer and q32 intermediate buffer.
     *
     * Register plan:
     *   v0-v3   (M4 e32): Accumulator pixel 1
     *   v4-v7   (M4 e32): Accumulator pixel 2
     *   v8-v11  (M4 e32): Accumulator pixel 3
     *   v12-v15 (M4 e32): Accumulator pixel 4
     *   v16     (M1 e8):  Weight vector load
     */
    const int in_tensor_ch = 3;
    long i_ker_y, i_ker_x, ch;

    const long align_byte = 64;
    q7_t *pOut = out_tensor;
    long vl;

    /* Allocate transposed weight buffer from in_tmp_buf */
    q7_t *src2 = (q7_t *)in_tmp_buf;
    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);

    /* Transpose weights once: from [out_ch x K] to [K x out_ch] */
    const long row = out_tensor_ch;
    const long col = ker_dim * ker_dim * in_tensor_ch;
    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);

    /* Total output pixels */
    long total_pixels = (long)out_tensor_dim * out_tensor_dim;
    long pixel_idx = 0;

    /* Process 4 output pixels at a time */
    for (; pixel_idx + 3 < total_pixels; pixel_idx += 4)
    {
        long out_y1 = pixel_idx / out_tensor_dim;
        long out_x1 = pixel_idx % out_tensor_dim;
        long out_y2 = (pixel_idx + 1) / out_tensor_dim;
        long out_x2 = (pixel_idx + 1) % out_tensor_dim;
        long out_y3 = (pixel_idx + 2) / out_tensor_dim;
        long out_x3 = (pixel_idx + 2) % out_tensor_dim;
        long out_y4 = (pixel_idx + 3) / out_tensor_dim;
        long out_x4 = (pixel_idx + 3) % out_tensor_dim;

        /* Load bias into 4 M4 accumulators at e32/M4 */
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VLE32_V(NDS_VEC_V0, bias);
        NDS_VEC_VLE32_V(NDS_VEC_V4, bias);
        NDS_VEC_VLE32_V(NDS_VEC_V8, bias);
        NDS_VEC_VLE32_V(NDS_VEC_V12, bias);

        /* Set e8/M1 once for all vqmacc accumulation (e8*e8->e32, M1 input, M4 acc) */
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);

        /* Accumulate over all K positions */
        if (pad == 0)
        {
            /* Fast path: no padding means all pixels are interior — skip boundary checks */
            for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
            {
                long in_row1 = out_y1 * stride + i_ker_y;
                long in_row2 = out_y2 * stride + i_ker_y;
                long in_row3 = out_y3 * stride + i_ker_y;
                long in_row4 = out_y4 * stride + i_ker_y;

                for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                {
                    long in_col1 = out_x1 * stride + i_ker_x;
                    long in_col2 = out_x2 * stride + i_ker_x;
                    long in_col3 = out_x3 * stride + i_ker_x;
                    long in_col4 = out_x4 * stride + i_ker_x;
                    long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;

                    for (ch = 0; ch < in_tensor_ch; ch++)
                    {
                        long k_pos = k_base + ch;

                        /* Load transposed weight row into v16 at e8/M1 */
                        NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch);

                        /* Get input scalars — no boundary checks needed */
                        q7_t a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                        q7_t a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
                        q7_t a3 = in_tensor[(in_row3 * in_tensor_dim + in_col3) * in_tensor_ch + ch];
                        q7_t a4 = in_tensor[(in_row4 * in_tensor_dim + in_col4) * in_tensor_ch + ch];

                        /* vqmacc.vx: acc[e32/M4] += scalar * wt[e8/M1] */
                        NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                        NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
                        NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
                        NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
                    }
                }
            }
        }
        else
        {
            /* General path: check boundaries for padding */
            for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
            {
                long in_row1 = out_y1 * stride - pad + i_ker_y;
                long in_row2 = out_y2 * stride - pad + i_ker_y;
                long in_row3 = out_y3 * stride - pad + i_ker_y;
                long in_row4 = out_y4 * stride - pad + i_ker_y;

                for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                {
                    long in_col1 = out_x1 * stride - pad + i_ker_x;
                    long in_col2 = out_x2 * stride - pad + i_ker_x;
                    long in_col3 = out_x3 * stride - pad + i_ker_x;
                    long in_col4 = out_x4 * stride - pad + i_ker_x;
                    long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;

                    for (ch = 0; ch < in_tensor_ch; ch++)
                    {
                        long k_pos = k_base + ch;

                        /* Load transposed weight row into v16 at e8/M1 */
                        NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch);

                        /* Get input scalars with boundary checks */
                        q7_t a1 = 0, a2 = 0, a3 = 0, a4 = 0;
                        if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
                            in_col1 >= 0 && in_col1 < in_tensor_dim)
                            a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                        if (in_row2 >= 0 && in_row2 < in_tensor_dim &&
                            in_col2 >= 0 && in_col2 < in_tensor_dim)
                            a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
                        if (in_row3 >= 0 && in_row3 < in_tensor_dim &&
                            in_col3 >= 0 && in_col3 < in_tensor_dim)
                            a3 = in_tensor[(in_row3 * in_tensor_dim + in_col3) * in_tensor_ch + ch];
                        if (in_row4 >= 0 && in_row4 < in_tensor_dim &&
                            in_col4 >= 0 && in_col4 < in_tensor_dim)
                            a4 = in_tensor[(in_row4 * in_tensor_dim + in_col4) * in_tensor_ch + ch];

                        /* vqmacc.vx: acc[e32/M4] += scalar * wt[e8/M1] */
                        NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                        NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
                        NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
                        NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
                    }
                }
            }
        }

        /* Requantize pixel 1: shift, scale, narrow, clip, store */
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
        NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, 0);
        NDS_VEC_VSB_V(NDS_VEC_V0, pOut);
        pOut += out_tensor_ch;

        /* Requantize pixel 2 */
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VSRA_VX(NDS_VEC_V4, NDS_VEC_V4, pre_rshift);
        NDS_VEC_VMUL_VX(NDS_VEC_V4, NDS_VEC_V4, out_scale);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V4, NDS_VEC_V4, post_rshift);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V4, NDS_VEC_V4, 0);
        NDS_VEC_VSB_V(NDS_VEC_V4, pOut);
        pOut += out_tensor_ch;

        /* Requantize pixel 3 */
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VSRA_VX(NDS_VEC_V8, NDS_VEC_V8, pre_rshift);
        NDS_VEC_VMUL_VX(NDS_VEC_V8, NDS_VEC_V8, out_scale);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V8, NDS_VEC_V8, post_rshift);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V8, NDS_VEC_V8, 0);
        NDS_VEC_VSB_V(NDS_VEC_V8, pOut);
        pOut += out_tensor_ch;

        /* Requantize pixel 4 */
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VSRA_VX(NDS_VEC_V12, NDS_VEC_V12, pre_rshift);
        NDS_VEC_VMUL_VX(NDS_VEC_V12, NDS_VEC_V12, out_scale);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V12, NDS_VEC_V12, post_rshift);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V12, NDS_VEC_V12, 0);
        NDS_VEC_VSB_V(NDS_VEC_V12, pOut);
        pOut += out_tensor_ch;
    }

    /* Handle remaining 0-3 pixels one at a time */
    for (; pixel_idx < total_pixels; pixel_idx++)
    {
        long out_y1 = pixel_idx / out_tensor_dim;
        long out_x1 = pixel_idx % out_tensor_dim;

        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VLE32_V(NDS_VEC_V0, bias);

        /* Set e8/M1 once for all vqmacc accumulation */
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);

        if (pad == 0)
        {
            /* Fast path: no padding — skip boundary checks */
            for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
            {
                long in_row1 = out_y1 * stride + i_ker_y;
                for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                {
                    long in_col1 = out_x1 * stride + i_ker_x;
                    long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
                    for (ch = 0; ch < in_tensor_ch; ch++)
                    {
                        long k_pos = k_base + ch;
                        NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch);
                        q7_t a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                        NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                    }
                }
            }
        }
        else
        {
            /* General path: check boundaries for padding */
            for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
            {
                long in_row1 = out_y1 * stride - pad + i_ker_y;
                for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
                {
                    long in_col1 = out_x1 * stride - pad + i_ker_x;
                    long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
                    for (ch = 0; ch < in_tensor_ch; ch++)
                    {
                        long k_pos = k_base + ch;
                        NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch);
                        q7_t a1 = 0;
                        if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
                            in_col1 >= 0 && in_col1 < in_tensor_dim)
                            a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                        NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                    }
                }
            }
        }

        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
        NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, 0);
        NDS_VEC_VSB_V(NDS_VEC_V0, pOut);
        pOut += out_tensor_ch;
    }
#else /* NDS_VEC_RVV_VERSION < 1000: fallback to tiling GEMM */
    //cache is 512KB, type is q7
    uint32_t tiling_size = 256;
    //num of columnar
    int col_counter = 0;
    const int in_tensor_ch = 3;
    int16_t    i_out_y, i_out_x, i_ker_y, i_ker_x;
    unsigned long addr_in_tmp_buf;

    /*
     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
     *  im2col are done to output in q15_t format from q7_t input
     */
    const long align_byte = 64;
    q7_t *pBuffer = (q7_t*)in_tmp_buf;
    q7_t *pOut = out_tensor;
    q31_t *dst_q31;
#ifdef DCACHE_SIZE
    int i;
    int tiling_size_arr[] = { 1,8,16,32,64,128,256,512,1024,2048 };
    int max_tile_size_in_cache = sqrt(((DCACHE_SIZE) << 10) / 6); //sqrt(((DCACHE_SIZE) << 10) / 3 / sizeof(float16_t))
    for (i = 1; i < sizeof(tiling_size_arr) / sizeof(tiling_size_arr[0]); i++)
    {
        if (tiling_size_arr[i] > max_tile_size_in_cache)
        {
            tiling_size = tiling_size_arr[i - 1];
            break;
        }
    }
#endif
#ifdef ENA_8MHVM
    char *hvm_base = (char *)0x90000000;
    q7_t *src2 = (q7_t *)hvm_base;
    addr_in_tmp_buf = (unsigned long)src2 + sizeof(*ker_weight) * in_tensor_ch * ker_dim * ker_dim * out_tensor_ch;
#else
    q7_t *src2 = (q7_t *)in_tmp_buf
                         + sizeof(*in_tensor) * tiling_size * in_tensor_ch * ker_dim * ker_dim; //matrix_A's memory space
    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);  // align the starting addresss
    addr_in_tmp_buf = (unsigned long)src2;
    addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch * ker_dim * ker_dim;
#endif
    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
    dst_q31 = (q31_t *)addr_in_tmp_buf;

    /* initial the output */
    nn_set_zero_s16((q15_t *)dst_q31, (tiling_size * out_tensor_ch * 2));

    // transpose the kernel_weight for matrix multiplication
    const long row = out_tensor_ch;
    const long col = ker_dim * ker_dim * in_tensor_ch;
    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);

    /* This part implements the im256col function */
    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        /* Filling 0 for out-of-bound paddings */
                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
                    }
                    else
                    {
                        /* Copying the pixel data to column */
                        nn_dup_s8((q7_t *)in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }
            col_counter++;

            /* Computation is filed for [tiling_size] columns */
            if (col_counter == tiling_size)
            {
                pOut = nn_mat_mul_kernel_tiling_q7((q7_t *)in_tmp_buf,
                                                   src2,
                                                   dst_q31,
                                                   pOut,
                                                   col_counter,
                                                   in_tensor_ch * ker_dim * ker_dim,
                                                   out_tensor_ch,
                                                   pre_rshift,
                                                   out_scale,
                                                   post_rshift,
                                                   bias,
                                                   tiling_size);
                /* reset */
                col_counter = 0;
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }
    }

    /* check if there is left-over for compute */
    pOut = nn_mat_mul_kernel_tiling_q7((q7_t*)in_tmp_buf,
                                       src2,
                                       dst_q31,
                                       pOut,
                                       col_counter,
                                       in_tensor_ch * ker_dim * ker_dim,
                                       out_tensor_ch,
                                       pre_rshift,
                                       out_scale,
                                       post_rshift,
                                       bias,
                                       tiling_size);
#endif /* NDS_VEC_RVV_VERSION >= 1000 */
#else
    long   i_out_y, i_out_x, i_ker_y, i_ker_x;

    /*
     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
     *  im2col are done to output in q15_t format from q7_t input
     */
    q7_t *pBuffer = (q7_t *)in_tmp_buf;
    q7_t *pOut = out_tensor;

    long buf_len = (3 * ker_dim * ker_dim);
    long vl;

    // This part implements the im2col function
    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            // init in_tmp_buf
            long len = buf_len;
            q7_t *pBuffer2 = pBuffer;
            NDS_VEC_VSETVLI(vl, len, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V24, NDS_VEC_V24, 0);   //zero
            while(len > 0)
            {
                NDS_VEC_VSB_V(NDS_VEC_V24, pBuffer2);
                len -= vl;
                pBuffer2 += vl;
                NDS_VEC_VSETVLI(vl, len, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            }

            // if (i_ker_y < 0)
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < 0; i_ker_y++)
            {
                pBuffer += ker_dim * 3;
            }

            long bound_y = ((i_out_y * stride - pad + ker_dim) < in_tensor_dim)? (i_out_y * stride - pad + ker_dim) : in_tensor_dim;
            for (; i_ker_y < bound_y; i_ker_y++)
            {
                // if (i_ker_x < 0)
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < 0; i_ker_x++)
                {
                    pBuffer += 3;
                }

                long bound_x = (i_out_x * stride - pad + ker_dim < in_tensor_dim)? (i_out_x * stride - pad + ker_dim) : in_tensor_dim;
                const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
                long loop = (bound_x - i_ker_x)*3;
                i_ker_x = bound_x;
                while(loop > 0)
                {
                    NDS_VEC_VSETVLI(vl, loop, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLB_V(NDS_VEC_V0, pPixel);
                    NDS_VEC_VSB_V(NDS_VEC_V0, pBuffer);
                    pPixel += vl;
                    pBuffer += vl;
                    loop -= vl;
                }

                // if (i_ker_x >= in_tensor_dim)
                for ( ; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    pBuffer += 3;
                }
            }

            // if (i_ker_y >= in_tensor_dim)
            for (; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                pBuffer += ker_dim * 3;
            }

            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim))
            {
                pOut = nn_mat_mul_kernel_q7_bias_2sft((q7_t *)ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim, pre_rshift, out_scale, post_rshift, bias, pOut);
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }
    }

#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        unsigned vl;
        const q7_t *p_wt = ker_weight;
        int       i;
        uint16_t  colCnt = 3 * ker_dim * ker_dim;
        // long vlenb = NDS_VEC_CSR_GET_VLENB();

#if (__clang__)
        register const long zero asm ("x0") = 0;
#else
        register const long zero asm ("x0");
#endif

        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0x0);     //const zero for redsum

        for (i = 0; i < out_tensor_ch; i++)
        {
            q7_t      *p_in = (q7_t*)in_tmp_buf;
            uint16_t colCnt2 = colCnt;

            //clear v0~v7
            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);

            // while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
            // {
            //     NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            //     //load src1
            //     NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
            //     //load src2
            //     NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
            //     //bump pointers and update loop counter
            //     colCnt2 -= vl;
            //     p_wt += vl;
            //     p_in += vl;
            //     //set the proper avl/SEW/LMUL values for vd4dot
            //     vl >>= 2;
            //     NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            //     //acc += src1 * src2
            //     NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            // }

            //extra process for the case of elements to be dot producted is not a mutiple of 4
            while(colCnt2 > 0)
            {
                //clean one of the dot product source
                NDS_VEC_VSETVLI(vl, zero, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);

                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                //load src1
                NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
                //load src2
                NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
                //bump pointers and update loop counter
                colCnt2 -= vl;
                p_wt += vl;
                p_in += vl;
                //set the proper avl/SEW/LMUL values for vd4dot
                //remember to deal with the elements to be dot producted is not a multiple of 4 case
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                //acc += src1 * src2
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            }

            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);  //note the avl here
            NDS_VEC_VREDSUM_VS(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V31);

            //add bias back
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VLW_V(NDS_VEC_V9, bias);
            NDS_VEC_VADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V9);

            //2-stage shift
            NDS_VEC_VSRA_VX(NDS_VEC_V8, NDS_VEC_V8, pre_rshift);
            NDS_VEC_VMUL_VX(NDS_VEC_V8, NDS_VEC_V8, out_scale);
            NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, NN_ROUND(post_rshift));

            //scale down, clip and store the results
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, post_rshift);
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
            NDS_VEC_VSB_V(NDS_VEC_V8, pOut);
            bias += vl;
            pOut += vl;
        }
    }
#elif (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ISA_ZVQMAC)
    /* left-over because odd number of output pixels */
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        long i;
        /* basically each time it process 4 entries */
        long colCnt = (3 * ker_dim * ker_dim);

        //set SEW for 1st time VMV_S_X
        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);

        for (i = 0; i < out_tensor_ch; i++)
        {
            q31_t sum = bias[i];
            q7_t *pB = (q7_t*)in_tmp_buf;
            long colCnt2 = colCnt;

            //init
            NDS_VEC_VMV_S_X(NDS_VEC_V0, sum);
            //clear v8~v15 (acc)
            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);

            while(colCnt2 > 0)
            {
                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                NDS_VEC_VLB_V(NDS_VEC_V2, pA);
                NDS_VEC_VLB_V(NDS_VEC_V4, pB);
                NDS_VEC_VQMACC_VV(NDS_VEC_V8, NDS_VEC_V2, NDS_VEC_V4);
                //bump pointers and update loop counter
                colCnt2 -= vl;
                pA += vl;
                pB += vl;
            }

            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V1, NDS_VEC_V8, NDS_VEC_V0);
            //move vr results to gpr
            NDS_VEC_VMV_X_S(sum, NDS_VEC_V1);

            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = NDS_ISA_SATS((sum >> post_rshift), 8);
        }
    }
#elif (NDS_VEC_RVV_VERSION == 80)
    /* left-over because odd number of output pixels */
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int i;
        /* basically each time it process 4 entries */
        uint16_t colCnt = (3 * ker_dim * ker_dim);

        //set SEW for 1st time VMV_S_X
        //LMUL=2 is just for clear v2~v3 (vmv ignores LMUL)
        NDS_VEC_VSETVLI_E32_M2(vl, colCnt);

        for (i = 0; i < out_tensor_ch; i++)
        {
            q31_t sum = bias[i];
            q7_t *pB = (q7_t*)in_tmp_buf;
            uint16_t colCnt2 = colCnt;

            //init
            NDS_VEC_VMV_S_X(NDS_VEC_V4, sum);
            //clear v2~v3 (acc)
            NDS_VEC_VAND_VI(NDS_VEC_V2, NDS_VEC_V2, 0x0);

            while(colCnt2 > 0)
            {
                NDS_VEC_VSETVLI_E16(vl, colCnt2);
                NDS_VEC_VLB_V(NDS_VEC_V0, pA);
                NDS_VEC_VLB_V(NDS_VEC_V1, pB);
                NDS_VEC_VWMACC_VV(NDS_VEC_V2, NDS_VEC_V1, NDS_VEC_V0);
                //bump pointers and update loop counter
                colCnt2 -= vl;
                pA += vl;
                pB += vl;
            }

            NDS_VEC_VSETVLI_E32_M2(vl, colCnt);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V4, NDS_VEC_V2, NDS_VEC_V4);
            //move vr results to gpr
            NDS_VEC_VMV_X_S(sum, NDS_VEC_V4);

            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = (q7_t) NDS_ISA_SATS((sum >> post_rshift), 8);
        }
    }
#endif
#endif
#elif defined(ENA_DSP_ISA_V5)
    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;

    /*
     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
     *  im2col are done to output in q15_t format from q7_t input
     */
    q7_t *wt_tmp = (q7_t*)ker_weight;

    q7_t    *pBuffer = (q7_t *)in_tmp_buf;
    q7_t     *pOut = out_tensor;

    uint32_t i;
    q7_t    *pBufferB = (q7_t *)wt_tmp_buf;

    uint16_t totalsize = 3 * ker_dim * ker_dim;
    for (i = 0; i < out_tensor_ch; i++)
    {
        uint32_t j;
        for (j = 0; j < totalsize; j++)
        {
            *pBufferB++ = *wt_tmp++;
        }
        *pBufferB++ = 0;
    }

    // This part implements the im2col function
    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        *pBuffer++ = 0;
                        *pBuffer++ = 0;
                        *pBuffer++ = 0;
                    }
                    else
                    {
                        const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
                        *pBuffer++ = *pPixel++;
                        *pBuffer++ = *pPixel++;
                        *pBuffer++ = *pPixel++;
                    }
                }
            }
            *pBuffer++ = 0;

            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim + 1))
            {
                pOut = nn_mat_mul_kernel_q7_bias_2sft((q7_t *)wt_tmp_buf, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim + 1, pre_rshift, out_scale, post_rshift, bias, pOut);
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }
    }

    /* left-over because odd number of output pixels */
#ifdef ENA_DSP_ISA_64
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int i;

        for (i = 0; i < out_tensor_ch; i++)
        {
            long sum = 0;
            q7_t *pB = (q7_t*)in_tmp_buf;

            /* basically each time it process 8 entries */
            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 3;

            while (colCnt)
            {
                long inA1, inB1;
                inA1 = *__SIMD64(pA)++;
                inB1 = *__SIMD64(pB)++;
                sum = NDS_DSP_SMAQA(sum, inA1, inB1);
                colCnt--;
            }
            //sum up the high and low part results (SIMD results)
            sum = (q31_t)(sum >> 32) + (q31_t)sum;

            colCnt = 3 * ker_dim * ker_dim & 0x7;
            while (colCnt)
            {
                q7_t inA1 = *pA++;
                q7_t inB1 = *pB++;
                sum += inA1 * inB1;
                colCnt--;
            }

            //add bias back
            sum += *bias++;

            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
        }
    }
#else
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int i;

        for (i = 0; i < out_tensor_ch; i++)
        {
            long sum = *bias++;
            q7_t *pB = (q7_t*)in_tmp_buf;

            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;
            while (colCnt)
            {
                long inA1, inB1;
                inA1 = *__SIMD32(pA)++;
                inB1 = *__SIMD32(pB)++;
                sum = NDS_DSP_SMAQA(sum, inA1, inB1);
                colCnt--;
            }

            colCnt = 3 * ker_dim * ker_dim & 0x3;
            while (colCnt)
            {
                q7_t inA1 = *pA++;
                q7_t inB1 = *pB++;
                sum += inA1 * inB1;
                colCnt--;
            }

            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
        }
    }
#endif
#elif defined(ENA_DSP_ISA)
    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;

    /*
     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
     *  im2col are done to output in q15_t format from q7_t input
     */
    q7_t *wt_tmp = (q7_t*)ker_weight;
    q15_t *pBuffer = in_tmp_buf;
    q7_t *pOut = out_tensor;

    uint32_t i;
    uint16_t size;
    uint16_t size2 = (3 * ker_dim * ker_dim) >> 2;
    q31_t tmp;
    q31_t *pwt2 = (q31_t *)wt_tmp_buf;
    for (i = 0; i < out_tensor_ch; i++)
    {
        size = size2;
        while (size != 0)
        {
            tmp = *__SIMD32(wt_tmp)++;;
            *pwt2++ = NDS_DSP_SUNPKD810(tmp);
            *pwt2++ = NDS_DSP_SUNPKD810(tmp >> 16);
            size--;
        }
        q7_t tmp1 = *wt_tmp++;
        q7_t tmp2 = *wt_tmp++;
        *pwt2++ = NDS_DSP_PKBB16(tmp2, tmp1);
        tmp1 = *wt_tmp++;
        *pwt2++ = (u16_t)tmp1;
    }

    // This part implements the im2col function
    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        *pBuffer++ = 0;
                        *pBuffer++ = 0;
                        *pBuffer++ = 0;
                    }
                    else
                    {
                        const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
                        *pBuffer++ = *pPixel++;
                        *pBuffer++ = *pPixel++;
                        *pBuffer++ = *pPixel++;
                    }
                }
            }
            *pBuffer++ = 0;

            if (pBuffer == in_tmp_buf + 2 * (3 * ker_dim * ker_dim + 1))
            {
                pOut = nn_mat_mul_kernel_q15_q15_q7_bias_2sft(wt_tmp_buf, in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim + 1, pre_rshift, out_scale, post_rshift, bias, pOut);
                pBuffer = in_tmp_buf;
            }
        }
    }

    if (pBuffer != in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int i;

        for (i = 0; i < out_tensor_ch; i++)
        {
            q31_t   sum = bias[i];
            q15_t   *pB = in_tmp_buf;

            /* basically each time it process 4 entries */
            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;

            while (colCnt)
            {
                q31_t     inA1, inA2;
                q31_t     inB1, inB2;

                pA = (q7_t *) read_and_pad((void *)pA, &inA1, &inA2);
                inB1 = *__SIMD32(pB)++;
                sum = NDS_DSP_KMADA(sum, inA1, inB1);
                inB2 = *__SIMD32(pB)++;
                sum = NDS_DSP_KMADA(sum, inA2, inB2);

                colCnt--;
            }
            colCnt = 3 * ker_dim * ker_dim & 0x3;
            while (colCnt)
            {
                q7_t      inA1 = *pA++;
                q15_t     inB1 = *pB++;
                sum += inA1 * inB1;
                colCnt--;
            }

            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
        }
    }
#else
    uint16_t  i, j, k, l, m, n;
    int       conv_out;
    long in_row, in_col;

    for (i = 0; i < out_tensor_ch; i++)
    {
        for (j = 0; j < out_tensor_dim; j++)
        {
            for (k = 0; k < out_tensor_dim; k++)
            {
                conv_out = bias[i];
                for (m = 0; m < ker_dim; m++)
                {
                    for (n = 0; n < ker_dim; n++)
                    {
                        /* if-for implementation */
                        in_row = stride * j + m - pad;
                        in_col = stride * k + n - pad;
                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
                        {
                            for (l = 0; l < 3; l++)
                            {
                                conv_out +=
                                    in_tensor[(in_row * in_tensor_dim + in_col) * 3 + l]
                                    * ker_weight[i * 3 * ker_dim * ker_dim + (m * ker_dim + n) * 3 + l];
                            }
                        }
                    }
                }
                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
                out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 8);
            }
        }
    }
#endif

    return 0;
}
